def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins)
    for i, capacity in enumerate(bins):
        if capacity <= 0:
            priorities[i] = float('inf')
            continue
        ratio = item / capacity
        if ratio > 2:
            priorities[i] = 2000 + (ratio - 2) * 200
        elif 1 < ratio <= 2:
            priorities[i] = 500 + (ratio - 1) * 100
        elif ratio == 1:
            priorities[i] = 150
        else:
            score = 0
            for j in range(1, 10):
                temp = ((capacity - item) ** j) / (capacity ** j)
                if temp < 0.05:
                    score += temp * 100
                elif 0.05 <= temp < 0.2:
                    score += temp * 20 / j
                else:
                    score += temp * 5 / (j ** 2)
            if score < 0.05:
                priorities[i] = score * 20
            elif 0.05 <= score < 0.3:
                priorities[i] = 1 / (score + 0.5)
            else:
                adjustment = 0
                for k in range(1, 4):
                    adjustment += ((item / (capacity + k)) ** k) * 10 / (k + 1)
                priorities[i] = 1 / (score + 1) + adjustment
        if capacities := capacity - item < 0.1 * capacity:
            priorities[i] += 0.1 * (capacity - item)
        if item > capacity * 0.9:
            priorities[i] *= 0.9
        if i % 2 == 0:
            priorities[i] += 1 / (capacity + 1)
        else:
            priorities[i] -= 1 / (capacity + 2)
    return priorities
